import React, { useState, useEffect } from 'react';
import { getSkills } from '../api';

const Skills = () => {
  const [skillCategories, setSkillCategories] = useState([]);
  const [loading, setLoading] = useState(true);

  // Load skills from database
  useEffect(() => {
    loadSkills();
  }, []);

  const loadSkills = async () => {
    try {
      setLoading(true);
      const response = await getSkills();
      setSkillCategories(response.data);
    } catch (error) {
      console.error('Error loading skills:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <section className="relative z-10 py-16 px-6">
        <div className="max-w-6xl mx-auto text-center text-gray-400">
          <div className="flex justify-center items-center gap-2">
            <div className="w-4 h-4 bg-purple-500 rounded-full animate-pulse"></div>
            <div className="w-4 h-4 bg-purple-500 rounded-full animate-pulse delay-100"></div>
            <div className="w-4 h-4 bg-purple-500 rounded-full animate-pulse delay-200"></div>
          </div>
          <p className="mt-4">Loading skills...</p>
        </div>
      </section>
    );
  }

  return (
    <section id="skills" className="relative z-10 py-16 px-6">
      <div className="max-w-6xl mx-auto">
        <h2 className="text-sm uppercase tracking-widest text-gray-500 font-semibold mb-8">Skills</h2>

        <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {skillCategories.map((category) => (
            <div key={category._id} className="glass-card rounded-2xl p-5 hover:border-purple-500/30 transition-all duration-300 flex flex-col h-full">

              {/* Category Header */}
              <h3 className="text-white font-semibold text-sm mb-3">{category.category}</h3>

              {/* Skills List */}
              <div className="flex flex-wrap gap-1.5 min-h-[40px]">
                {category.skills.map((skill, idx) => (
                  <span key={idx} className="inline-flex items-center text-xs bg-purple-500/10 text-purple-300 px-2.5 py-1 rounded-full border border-purple-500/10">
                    {skill}
                  </span>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Skills;
